#include<bits/stdc++.h>
using namespace std;
vector<int> mp[100010];
int a[100010],n,ans,sum[100010],max1[100010];
void dfs(int x,int fa=-1)
{
    sum[x]=a[x];
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            sum[x]+=sum[i];
            max1[x]=max(max1[x],sum[i]);
        }
    }
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs(1);
    for(int i=1;i<=n;i++)
    {
        if((sum[i]!=0&&sum[1]-sum[i]!=0)||sum[i]!=max1[i])
        {
            ans+=1-a[i];
        }
    }
    printf("%d",ans);
    return 0;
}
